parameters.text:
=Compare these two policies and list the changes.

Policy V1:
{{$json.previousPolicy}}

Policy V2:
{{$json.newPolicy}}

parameters.inputSchema:
{
  "changes": [
    "string describing each detected policy change"
  ],
  "employees": [
    {
      "id": "string unique employee ID",
      "name": "string full name",
      "email": "string email address",
      "department": "string department name",
      "location": "string office/location",
      "tenure_years": 0,
      "tenure_months": 0
    }
  ],
  "notifications": [
    {
      "id": "string unique notification ID",
      "employeeId": "string corresponding employee ID",
      "employeeName": "string employee full name",
      "message": "string personalized message/email content",
      "status": "draft"
    }
  ]
}

parameters.jsCode:
const items = $input.all();

// Clean function
const clean = (text) => {
  return text
    .replace(/•/g, "")
    .replace(/\r?\n|\r/g, " ")
    .replace(/\s+/g, " ")
    .trim();
};

// Map both documents
const previousPolicy = clean(items[0].json.text);
const newPolicy = clean(items[1].json.text);

// Return SINGLE item
return [
  {
    json: {
      previousPolicy,
      newPolicy
    }
  }
];
